// Map RSS items into PULSE story shape and wrap as one JSON file.
// Duplicate the RSS node per category and set `cat` accordingly, then
// merge before this node, OR run separate branches and combine.
const CAT = 'World';
const items = $input.all();
const stories = items.slice(0, 8).map((it, i) => {
  const j = it.json;
  const url = j.link || j.url || '';
  return {
    cat: CAT,
    ...(i === 0 ? { lead: true } : {}),
    title: j.title || '',
    summary: (j.contentSnippet || j.content || j.description || '').replace(/<[^>]+>/g, '').slice(0, 200),
    source: url.replace(/^https?:\/\/(www\.)?/, '').split('/')[0],
    url
  };
}).filter(s => s.title && s.url);
const out = {
  date: new Date().toISOString().slice(0, 10),
  updated: new Date().toISOString(),
  brand: 'PULSE',
  stories
};
return [{ json: out }];
